if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const raw = $input.first().json;
let text = '';
if (raw.content && Array.isArray(raw.content)) text = raw.content.map(c => c.text || '').join('');
else text = JSON.stringify(raw);
let parsed = { events: [] };
try { const clean = text.replace(/```json/g,'').replace(/```/g,'').trim(); parsed = JSON.parse(clean); } catch(e) { const m = text.match(/\{[\s\S]*\}/); if (m) try { parsed = JSON.parse(m[0]); } catch(e2) {} }
const events = parsed.events || [];
if (!events.length) return [{ json: { _hasData: false, msg: 'No DHS events found' } }];
return events.map(e => ({ json: { ...e, data_source: 'DHS Industry Day', stage: 'Pre-RFP', _hasData: true } }));

const items = $input.all();
const hasData = items.some(function(i) { return i.json._hasData !== false; });
return [{ json: { status: 'ok', workflow: 'GDA.sched.dhs-industry-day-monitor', events_found: hasData ? items.length : 0, timestamp: new Date().toISOString() } }];

